import { Component, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { AccountService, AlertService } from '@app/_services';
import { AlertComponent } from '@app/_components';    // ✅ fixes <alert> not a known element

@Component({
  selector: 'app-forgot-password',
  standalone: true,                                   // ✅ changed to standalone: true
  imports: [CommonModule, ReactiveFormsModule, RouterLink, AlertComponent],  // ✅ AlertComponent added
  templateUrl: './forgot-password.component.html'
})
export class ForgotPasswordComponent implements OnInit {
  form!: FormGroup;
  loading = false;    // ✅ 'loading' not 'submitting'
  submitted = false;

  constructor(
    private formBuilder: FormBuilder,
    private accountService: AccountService,
    private alertService: AlertService
  ) {}

  ngOnInit() {
    this.form = this.formBuilder.group({
      email: ['', [Validators.required, Validators.email]]
    });
  }

  get f() { return this.form.controls; }

  onSubmit() {
    this.submitted = true;
    this.alertService.clear();

    if (this.form.invalid) return;

    this.loading = true;
    this.accountService.forgotPassword(this.f['email'].value)
      .subscribe({
        next: () => {
          this.alertService.success('Please check your email for password reset instructions');
          this.loading = false;
        },
        error: error => {
          this.alertService.error(error);
          this.loading = false;
        }
      });
  }
}
